+        // Wire click-to-activate AND drag initiation on container.
+        // Click activates (focusTracker handles restore).
+        // Press+move beyond threshold initiates stamp drag.
+        let pressX = 0, pressY = 0;
+        let pressHandlerId = 0, motionCheckId = 0;
+        const DRAG_THRESHOLD = 8; // pixels
+
+        pressHandlerId = result.container.connect('button-press-event', (_actor, event) => {
+            if (event.get_button() !== Clutter.BUTTON_PRIMARY)
+                return Clutter.EVENT_PROPAGATE;
+            [pressX, pressY] = event.get_coords();
+
+            // Connect a motion handler to detect drag threshold
+            motionCheckId = result.container.connect('motion-event', (_a, motionEvent) => {
+                const [mx, my] = motionEvent.get_coords();
+                if (Math.abs(mx - pressX) > DRAG_THRESHOLD ||
+                    Math.abs(my - pressY) > DRAG_THRESHOLD) {
+                    // Drag threshold exceeded — start stamp drag
+                    result.container.disconnect(motionCheckId);
+                    motionCheckId = 0;
+                    this._dragHandler.startStampDrag(metaWindow, result.container);
+                }
                 return Clutter.EVENT_STOP;
+            });
+            return Clutter.EVENT_STOP;
+        });
+
+        result.container.connect('button-release-event', (_actor, event) => {
+            if (motionCheckId) {
+                // Motion threshold never exceeded — this is a click, not a drag
+                result.container.disconnect(motionCheckId);
+                motionCheckId = 0;
+                metaWindow.activate(global.get_current_time());
             }
-            return Clutter.EVENT_PROPAGATE;
+            return Clutter.EVENT_STOP;
         });
     }

